import{_ as i,c as l,o,ak as r}from"./chunks/framework.CYxz2ou1.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"NanoLife/A-书架/1-读书笔记/202305-曾国藩转.md","filePath":"NanoLife/A-书架/1-读书笔记/202305-曾国藩转.md","lastUpdated":1775467143000}'),a={name:"NanoLife/A-书架/1-读书笔记/202305-曾国藩转.md"};function n(e,t,s,g,_,d){return o(),l("div",null,[...t[0]||(t[0]=[r('<h2 id="📘-基本信息" tabindex="-1">📘 基本信息 <a class="header-anchor" href="#📘-基本信息" aria-label="Permalink to &quot;📘 基本信息&quot;">​</a></h2><ul><li><strong>📖</strong> <strong>书名</strong>：曾国藩转</li><li><strong>🕵️‍♂️</strong> <strong>作者</strong>：<strong>张宏杰</strong></li><li><strong>🥂</strong> <strong>推荐分数</strong>：9.5</li><li><strong>⏰</strong> <strong>阅读时间</strong>：<strong>2023 年 5 月</strong></li></ul><p>![[Pasted image 20260405130755.png|191]]</p><h2 id="📝-总结" tabindex="-1">📝 总结 <a class="header-anchor" href="#📝-总结" aria-label="Permalink to &quot;📝 总结&quot;">​</a></h2><p>因为有文言文，所以书看起来不是特别友好，有些吃力。曾国藩做人的智慧值得一直学习。</p><h2 id="📖-摘录" tabindex="-1">📖 摘录 <a class="header-anchor" href="#📖-摘录" aria-label="Permalink to &quot;📖 摘录&quot;">​</a></h2><ul><li>尚拙。</li><li><strong>读不懂上一句，不读下一句。不读完一本书，不摸下一本书</strong>。</li><li><strong>立德立功立言三不朽，为师为将为相一完人</strong>。</li><li>三十岁立志做王阳明这样的圣人。</li><li>进入翰林院考试都很顺利。得到了道光皇帝的赏识。意气风发。后咸丰继位，软弱无能。初入朝廷，锋芒毕露，直言批咸丰，得罪了皇帝，同时又因为上书说朝廷腐败得罪了大部分官员。人人唾弃。</li><li>当了十三年京官后，曾国藩对咸丰灰心，觉得咸丰不行。后咸丰派曾国藩去江西当主考官，途中得知母亲病逝，后回湖南守孝。</li><li>太平天国起义崛起，已经进入湖北。咸丰命曾国藩在湖南操练，保卫乡里。曾国藩极其强势，变身 “曾剃头”，遇到犯罪行为格杀勿论。同时做事过于雷厉风行不管他人，认为其他官员都是废物。各种行为也影响了其他官员的灰色收入，动了别人的蛋糕，因此被多数官员厌恶。</li><li>太平天国是整个中国传统文化的敌人，洪秀全企图毁掉一切书籍，寺庙，古文物建筑等。为了挽救人民与文化，曾国藩组建湘军。</li><li>组建湘军后，曾国藩并不急于让军队上战场，而是稳扎稳打的训练。后来打太平军十分顺利。</li><li>朝中有人给咸丰说曾国藩能轻易建立强大的湘军，如果要谋反也是可能的。咸丰听信。后来不断给曾国藩穿小鞋，并且不让曾国藩拥有实权。加之咸丰没有谋略，胡乱指挥，导致贻误战机。</li><li>胡林翼是曾国藩的好友，战场上互相配合。</li><li>湘军的战术：<strong>结硬寨，打呆仗</strong>。</li><li>咸丰没有战略头脑，胡乱指挥，经常延误战机。并且一直不给曾国藩实权。</li><li>曾国藩与好友胡林翼配合，取得了不少胜利。</li><li>曾国藩的弟弟曾国荃是著名将领。带兵收复南京，至此太平天国几乎瓦解。然而曾国荃被朝廷厌恶。曾国藩深知自己和弟弟一个带兵一个有权，肯定得不到朝廷的信任。因此撤裁湘军，让弟弟回家待命。这种自剪羽翼的行为让慈禧十分满意。</li><li>左宗棠对曾国藩有 &quot;瑜亮情结&quot;，因此经常与曾国藩作对。曾国藩死后，两人才算和解，左宗棠自愧不如曾国藩。</li><li>李鸿章是曾国藩的弟子。曾国藩极力培养李鸿章，后李鸿章接替了曾国藩成为晚清的外交，军事的实际掌权人。</li><li>曾国藩为股权大局，舍弃自己的名声，处理了棘手的 &quot;天津教案&quot;。</li></ul>',7)])])}const h=i(a,[["render",n]]);export{u as __pageData,h as default};
